import{_ as e,o as t,c as s,a2 as i}from"./chunks/framework.BZO4qERu.js";const r="/imgs/%E5%BB%B6%E8%BF%9F%E5%8A%A0%E8%BD%BD%E6%B5%81%E7%A8%8B%E5%9B%BE.png",m=JSON.parse('{"title":"Mybatis","description":"","frontmatter":{},"headers":[],"relativePath":"java/Mybatis.md","filePath":"java/Mybatis.md","lastUpdated":1780998639000}'),l={name:"java/Mybatis.md"};function o(n,a,h,c,d,p){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="mybatis" tabindex="-1">Mybatis <a class="header-anchor" href="#mybatis" aria-label="Permalink to &quot;Mybatis&quot;">​</a></h1><h1 id="mybatis执行流程" tabindex="-1">Mybatis执行流程 <a class="header-anchor" href="#mybatis执行流程" aria-label="Permalink to &quot;Mybatis执行流程&quot;">​</a></h1><ol><li>首先，依据mybatis-config.xml读取配置信息，包括数据库连接信息，需要使用哪些映射包。</li><li>然后通过会话构建工厂SqlSessionFactory构建多个SqlSession会话对象（包含执行SQL语句的方法】），工厂制定会话Session的功能，会话Session使用功能进行调用对应的Executor执行器（数据库功能接口，同时负责查询缓存维护）</li><li>MappedStatement用来读取写好的数据库SQL语句封装到自己的内部属性中，对于传入的参数以及返回的结果都进行数据类型转换，java类型与数据库类型之间的转换</li><li>然后Exector执行器通过MappedStatement来实现数据库相关功能</li><li>注意使用注解方法后，底层仍然采用的是这些流程，只是采用注解封装了起来而已。</li></ol><h1 id="mybatis的延迟加载" tabindex="-1">Mybatis的延迟加载 <a class="header-anchor" href="#mybatis的延迟加载" aria-label="Permalink to &quot;Mybatis的延迟加载&quot;">​</a></h1><h2 id="什么是延迟加载-默认不开启" tabindex="-1">什么是延迟加载（默认不开启） <a class="header-anchor" href="#什么是延迟加载-默认不开启" aria-label="Permalink to &quot;什么是延迟加载（默认不开启）&quot;">​</a></h2><p>例如用户表与订单表是一对多的关系，一个用户可以对应多个订单</p><p><strong>立即加载：<strong>查询用户的时候，把用户所属的订单数据也查询出来，这个是</strong>立即加载</strong></p><p><strong>延迟加载：<strong>查询户的时候，暂时不查询订单数据，当需要订单的时候，再查询订单，这个就是</strong>延迟加载</strong></p><ul><li>延迟加载的意思是：就是在需要用到数据时才进行加载，不需要用到数据时就不加载数据。</li><li>Mybatis支持一对一关联对象和一对多关联集合对象的延迟加载</li><li>在Mybatis配置文件中，可以配置是否启用延迟加载<strong>lazyLoadingEnabled=truelfalse</strong>，默认是关闭的</li></ul><h2 id="延迟加载的原理" tabindex="-1">延迟加载的原理 <a class="header-anchor" href="#延迟加载的原理" aria-label="Permalink to &quot;延迟加载的原理&quot;">​</a></h2><ol><li>使用CGLIB创建目标对象的代理对象</li><li>当调用目标方法user.getOrderList()时，进入拦截器invoke方法，发现user.getOrderListO是null值，执行sql查询order列表</li><li>把order查询上来，然后调用<code>user.setOrderList(List&lt;Order&gt;orderList)</code>，接着完成<code>user.getOrderList()</code>方法的调用</li></ol><p><img src="'+r+'" alt=""></p><h1 id="mybatis的一二级缓存" tabindex="-1">Mybatis的一二级缓存 <a class="header-anchor" href="#mybatis的一二级缓存" aria-label="Permalink to &quot;Mybatis的一二级缓存&quot;">​</a></h1><ol><li>一级缓存:基于PerpetualCache的HashMap本地缓存，其存储作用域为Session，当Session进行flush或close之后，该Session中的所有Cache就将清空，默认打开一级缓存</li><li>二级缓存是基于namespace和mapper的作用域起作用的，不是依赖于SQLsession，默认也是采用PerpetualCache，HashMap存储。需要单独开启，一个是核心配置，一个是mapper映射件</li></ol><h2 id="一级缓存" tabindex="-1">一级缓存 <a class="header-anchor" href="#一级缓存" aria-label="Permalink to &quot;一级缓存&quot;">​</a></h2><p>基于PerpetualCache的HashMap本地缓存，其<strong>存储作用域为 Session</strong>，范围较小</p><p>当Session进行flush或close之后，该Session中的所有Cache就将清空，<strong>默认打开一级缓存</strong></p><h2 id="二级缓存" tabindex="-1">二级缓存 <a class="header-anchor" href="#二级缓存" aria-label="Permalink to &quot;二级缓存&quot;">​</a></h2><p>二级缓存是<strong>基于namespace和mapper的作用域起作用</strong>的，不是依赖于SQL session，默认也是采用PerpetualCacheHashMap 存储</p><p>默认关闭，开启方式如下：</p><ol><li>配置文件把cacheEnabled设置为true</li><li>对应xml映射文件中加入<code>&lt;cache/&gt;</code>标签即可</li></ol><h2 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意&quot;">​</a></h2><ol><li>对于缓存数据更新机制，当<strong>某一个作用域(一级缓存 Session/二级缓存Namespaces)的进行了新增、修改、删除操作后，默认该作用域下所有select中的缓存将被clear</strong></li><li>二级缓存需要<strong>缓存的数据实现Serializable接口</strong></li><li>只有<strong>会话提交或者关闭以后，一级缓存中的数据才会转移到二级缓存中</strong></li></ol>',23)])])}const u=e(l,[["render",o]]);export{m as __pageData,u as default};
